import{_ as t,o as a,c as o,aB as r}from"./chunks/framework.k9Y_cM_f.js";const g=JSON.parse('{"title":"Inelastic Scattering","description":"","frontmatter":{},"headers":[],"relativePath":"pages/Inelastic/Overview.md","filePath":"pages/Inelastic/Overview.md","lastUpdated":null}'),i={name:"pages/Inelastic/Overview.md"};function n(l,e,s,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="Inelastic-Scattering" tabindex="-1">Inelastic Scattering <a class="header-anchor" href="#Inelastic-Scattering" aria-label="Permalink to &quot;Inelastic Scattering {#Inelastic-Scattering}&quot;">​</a></h1><p><strong>For:</strong> users choosing Raman/Cabannes modes and developers extending inelastic scattering.</p><p><strong>Next:</strong> <a href="./../vSmartMOM/CoreRTTheory">Core RT Theory</a>, <a href="./../extending/raman">Add a Raman Mode</a>, <a href="./../api_reference">Library</a>.</p><p>The <code>InelasticScattering</code> module defines the Raman mode types and molecular precomputations used by the CoreRT solver. The forward model can run without Raman redistribution, with rotational Raman scattering, or with vibrational Raman scattering modes.</p><p>This page documents the current public mode layer. Solar-induced fluorescence is intentionally not documented here until the product/data policy for shipped fixtures is settled.</p><h2 id="Mode-Types" tabindex="-1">Mode Types <a class="header-anchor" href="#Mode-Types" aria-label="Permalink to &quot;Mode Types {#Mode-Types}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Type</th><th style="text-align:right;">Meaning</th><th style="text-align:right;">Typical use</th></tr></thead><tbody><tr><td style="text-align:right;"><code>noRS</code></td><td style="text-align:right;">Pure elastic scattering mode with no Raman redistribution</td><td style="text-align:right;">Default mode for ordinary <code>rt_run(model)</code> calls</td></tr><tr><td style="text-align:right;"><code>RRS</code></td><td style="text-align:right;">Rotational Raman scattering for an N2/O2 atmosphere</td><td style="text-align:right;">Filling-in calculations over one spectral grid</td></tr><tr><td style="text-align:right;"><code>VS_0to1</code></td><td style="text-align:right;">Vibrational Stokes-style mode</td><td style="text-align:right;">Single vibrational transition family</td></tr><tr><td style="text-align:right;"><code>VS_1to0</code></td><td style="text-align:right;">Vibrational anti-Stokes-style mode</td><td style="text-align:right;">Single vibrational transition family</td></tr><tr><td style="text-align:right;"><code>noRS_plus</code></td><td style="text-align:right;">Elastic mode for concatenated-grid code paths</td><td style="text-align:right;">Plus-mode workflows that share Raman interfaces</td></tr><tr><td style="text-align:right;"><code>VS_0to1_plus</code></td><td style="text-align:right;">Vibrational Stokes-style plus mode</td><td style="text-align:right;">Concatenated-grid vibrational workflows</td></tr><tr><td style="text-align:right;"><code>VS_1to0_plus</code></td><td style="text-align:right;">Vibrational anti-Stokes-style plus mode</td><td style="text-align:right;">Concatenated-grid vibrational workflows</td></tr></tbody></table><p>The mode type is the dispatch key. CoreRT asks trait methods such as <code>has_inelastic</code>, <code>uses_cabannes_phase</code>, and <code>needs_interaction_workspace</code> what workspaces and optical-property transforms are needed for the selected mode.</p><h2 id="What-Gets-Precomputed" tabindex="-1">What Gets Precomputed <a class="header-anchor" href="#What-Gets-Precomputed" aria-label="Permalink to &quot;What Gets Precomputed {#What-Gets-Precomputed}&quot;">​</a></h2><p>Raman modes carry:</p><ul><li><p>molecular constants for the active species;</p></li><li><p>Raman and Cabannes/Rayleigh optical-property weights;</p></li><li><p>wavelength-redistribution indices;</p></li><li><p>Raman phase-function Greek coefficients;</p></li><li><p>solar or stellar irradiation arrays used by the inelastic source terms.</p></li></ul><p>Molecular constants are stored as <code>Float64</code> even when the RT work arrays use <code>Float32</code>. Raman cross-section prefactors can sit near the <code>Float32</code> subnormal range, so this mixed precision is intentional: molecular state remains stable while the solver arrays keep their configured element type.</p><h2 id="Current-Solver-Integration" tabindex="-1">Current Solver Integration <a class="header-anchor" href="#Current-Solver-Integration" aria-label="Permalink to &quot;Current Solver Integration {#Current-Solver-Integration}&quot;">​</a></h2><p>The inelastic path is not a separate solver. It is an alternate dispatch path through the same adding-doubling machinery:</p><ol><li><p>the selected Raman mode builds or normalizes the required optical properties;</p></li><li><p>CoreRT allocates only the workspaces required by that mode;</p></li><li><p>the elemental, doubling, and interaction kernels propagate the source terms through the layer stack.</p></li></ol><p>For the current code map, see the inelastic section of <a href="./../vSmartMOM/CoreRTTheory">Core RT Theory</a>.</p><h2 id="Useful-APIs" tabindex="-1">Useful APIs <a class="header-anchor" href="#Useful-APIs" aria-label="Permalink to &quot;Useful APIs {#Useful-APIs}&quot;">​</a></h2><ul><li><p><code>AbstractRamanType</code></p></li><li><p><code>noRS</code>, <code>RRS</code>, <code>VS_0to1</code>, <code>VS_1to0</code></p></li><li><p><code>noRS_plus</code>, <code>VS_0to1_plus</code>, <code>VS_1to0_plus</code></p></li><li><p><code>compute_γ_air_Cabannes!</code>, <code>compute_γ_air_Rayleigh!</code>, <code>apply_lineshape!</code></p></li></ul>',18)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
